var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"잠깐, 그 촌뜨기라고?","JPN":"待て、あの田舎者だと？","ENG":"What? That's the country bumpkin?","TWN":"什麼？那個鄉巴佬？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"여기서는 무대가 잘 안 보이잖아......! 플루토, 무등 좀 태워 줘!","JPN":"ここからは舞台がよく見えないんだ……！　プルートー、肩に乗せてくれ！","ENG":"I can't see the stage from here! Pluto, boost me up!","TWN":"這裡看不清楚舞臺……！布魯托，讓我騎一下！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐앙!?","JPN":"にゃあ？","ENG":"Meow?!","TWN":"喵！？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"설마 했는데...... 마지막 결선 진출자가 잉그리드였어?","JPN":"まさかとは思ったけど……決勝進出者ってイングリッドだったの？","ENG":"No way... Ingrid has made it to the finals?","TWN":"沒想到……真的是英格麗啊？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"앗! 저기 나오고 있어요!","JPN":"あっ！　あそこ！","ENG":"Oh! There she is!","TWN":"啊！她出來了！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"난 말이지, 마녀가 되는 게 꿈이었어.","JPN":"私はね、魔女になるのが夢だった。","ENG":"I always wanted to become a witch.","TWN":"我的夢想，是成為一個魔女。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"다들 바보 같은 꿈이라고, 황당하다고 비웃었지만 포기하지 않았다고.","JPN":"みんなにバカバカしい夢だって、絶対なれないって笑われたけど、諦めなかったんだ。","ENG":"Everyone told me it was a ridiculous dream, but I never gave up.","TWN":"雖然大家都嘲笑我的夢想非常荒謬，但我從來沒有放棄。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"그리고 이 할로윈의 밤에, 난 꿈을 이룰 거야.","JPN":"そしてこのハロウィンの夜に私の夢は叶う。","ENG":"And that dream will finally come true this Halloween night.","TWN":"而在這萬聖節之夜，我要實現我的夢想。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"그러니까, 짓궂은 장난으로 분위기 깨는 유령 녀석들은......","JPN":"だから、意地悪ないたずらで邪魔する幽霊どもは……","ENG":"So any mischievous ghosts who dare to disturb this solemn moment...","TWN":"所以，搗蛋的惡靈們……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"가만 안 두겠어!","JPN":"絶対に許さない！","ENG":"will face my wrath!","TWN":"受死吧！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"수확의 마녀! 잉그리드! 할로윈을 맞아 여기 도착!","JPN":"収穫の魔女！　イングリッド！　ハロウィンを迎えてここに参上！","ENG":"The Harvest Witch, Ingrid, has arrived on this Halloween day!","TWN":"惡靈獵手！英格麗！為了收割靈魂降臨此處！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"잉그리드! 멋져! 파이팅!","JPN":"イングリッド！　最高です！　ファイト！","ENG":"You're fantastic, Ingrid! Way to go!","TWN":"英格麗！妳好帥！加油！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"야옹~","JPN":"にゃあ～。","ENG":"Meow!","TWN":"喵喵~"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"견습치고는 제법이잖아. 그렇지 않아, 라우라?","JPN":"見習いにしてはなかなかね。そう思わない、ラウラ？","ENG":"Not bad for an apprentice. Don't you think so, Laura?","TWN":"作為見習還不賴嘛，是吧，蘿拉？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"머, 멋지잖아...... 촌뜨기 주제에......?","JPN":"か、格好いい……田舎者のくせに……？","ENG":"Th-that country bumpkin... actually looks pretty good...","TWN":"這個鄉巴佬……怎麼這麼帥……？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"왜 그래? 혹시 넋이 나갈 만큼 감동했니?","JPN":"どうしたの？　もしかして魂が抜けるほど感動したとか？","ENG":"What's wrong? Are you so moved that you're in a daze?","TWN":"怎麼了？帥的你魂不守舍了？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아, 아니야! 그냥 조금 놀랐을 뿐이야!","JPN":"ち、違う！　ただちょっと驚いただけだ！","ENG":"N-no! I'm just a little surprised, that's all!","TWN":"才、才不是！我只是稍微嚇到了而已！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"잉그리드 양의 감동적인 무대였습니다!","JPN":"イングリッドちゃんの感動的な舞台でした！","ENG":"A moving performance by Ms. Johanna!","TWN":"英格麗小姐的表演真讓人感動啊！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"자, 그럼 할로윈 코스튬 경연 대회의 우승자는 누구일까요?","JPN":"さあ、ではハロウィンコスチュームコンテストの優勝者を発表いたします。","ENG":"Now then, who shall be the winner of this year's Halloween costume contest?","TWN":"那麼，萬聖節扮裝大賽的冠軍會是誰呢？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"우승자는......","JPN":"優勝者は……","ENG":"And the winner is...","TWN":"冠軍……"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"야심차게 준비한 크로넨워스 인형극단의 퍼레이드 쇼 후에 발표하겠습니다!!","JPN":"念入りに準備されたクロネンワース人形劇団のパレードの後に発表いたします！！","ENG":"... going to be announced after the great parade by the Cronenworth Puppet Troupe!","TWN":"在克羅尼溫斯木偶劇團的表演之後將宣佈結果！！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"드디어 시작하나 봐요, 크로넨워스 극단의 인형 퍼레이드! 엄청 기대했는데!","JPN":"いよいよ始まるみたいですよ、クロネンワース人形劇団のパレード！　とっても楽しみ！","ENG":"Looks like they're finally getting started with the puppet parade! I was looking forward to it so much!","TWN":"克羅尼溫斯木偶劇團的木偶表演終於要開始了！我可是很期待啊！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"인형극단? 그런 거 관심 없어.","JPN":"人形劇団？　そんなものに興味ない。","ENG":"A puppet parade? I couldn't care less about something like that.","TWN":"木偶劇團？我沒興趣。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"우승자 발표나 빨리 할 것이지.","JPN":"さっさと優勝者の発表をすればいい。","ENG":"Why don't they just get on with the announcement of the winner?","TWN":"還不如趕緊宣佈冠軍呢。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"에이, 점장님도 한 번 보면 생각이 달라질 걸요?","JPN":"まぁまぁ、店長も一度見てみると気が変わると思います。","ENG":"Oh, come on. I'm sure you'll change your mind once you see it.","TWN":"哎呀，店長，您看完之後就知道多有趣了！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"이런. 미움 받을 타이밍에 소개를 받았네요.","JPN":"あら。タイミングの悪い時に紹介されてしまったようですね。","ENG":"Oh, my. I seemed to have butted in at the wrong time.","TWN":"很抱歉在這種關鍵時刻出來為大家表演。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"하지만 걱정 마세요.","JPN":"ですが、ご心配なく。","ENG":"But don't you worry.","TWN":"不過大家不用擔心。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"오늘 보여드릴 쇼는, 저희 극단이 처음 공개하는 비장의 공연이랍니다.","JPN":"今日お見せするショーは我が劇団が初めて公開する、とっておきの公演です。","ENG":"We're about to put on a show for you that our troupe has never performed live before.","TWN":"今天接下來的演出是我們劇團首次公開的秘密演出。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"......잠깐. 저 사람이 인형 극단 단장이야?","JPN":"……待て。あの人が人形劇団の団長なのか？","ENG":"Hang on, is that the troupe leader?","TWN":"……妳說，他是木偶劇團的團長？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"네? 아, 맞아요.","JPN":"え？　ああ、そうですよ。","ENG":"Huh? Oh, yeah. She is.","TWN":"嗯？對，是的。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"오늘 낮에 도와드렸다는 사람이 바로 저 분이에요.","JPN":"今日の昼に手伝ってあげたのがあの人です。","ENG":"She's the one I was helping out earlier today, actually.","TWN":"今天早上我幫的人就是他。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"처음 보는 얼굴인데 왜 이렇게 익숙하게 느껴지지?","JPN":"初めて見る顔だが、どこかで見覚えがあるような……","ENG":"I've never seen her before... so why does she seem so familiar?","TWN":"明明是第一次見，可怎麼感覺這麼熟悉？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"저 사람 이름이 뭐라고?","JPN":"名前は何だって？","ENG":"What's her name again?","TWN":"他叫什麼名字？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"하랍, 하랍 크로넨워스 씨에요.","JPN":"ハーラヴさんです。ハーラヴ·クロネンワースさん。","ENG":"Harab. Harab Cronenworth.","TWN":"哈拉普，哈拉普·克羅尼溫斯。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"공연을 시작하기 전에 한 가지 여러분들께 알려드리고 싶은 것이 있어요.","JPN":"公演を始める前に、皆さんに一つお教えしたいことがあります。","ENG":"There's something I'd like to let you know before we begin the show today.","TWN":"演出開始前，我想告訴大家一件事。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"많은 분들이 저희 극단에 있는 멋진 인형들을 어떻게 만드는지 궁금해 하시죠.","JPN":"多くの方々が我が劇団の素敵な人形の作り方について、気になっているかと思います。","ENG":"Many folks have been wondering how I make these wonderful puppets.","TWN":"很多人很好奇我們劇團的木偶是怎麼製作而成的。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"오늘은 특별히 그 비밀을 알려드리려고 해요.","JPN":"今日は特別にその秘密をお教えしたいと思います。","ENG":"So I will share that secret with you, just for today.","TWN":"今天我將公開這個秘密。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"오오, 정말인가요? ","JPN":"おぉ、本当ですか？ ","ENG":"Ooh, really? ","TWN":"哇，真的嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"크로넨워스 극단의 인형들은 그 섬세한 모습과 우아한 디자인으로 유명하죠.","JPN":"クロネンワース劇団の人形はその繊細な作り方とエレガントなデザインで有名です。","ENG":"The Cronenworth puppets are famous for their realistic yet sophisticated designs.","TWN":"克羅尼溫斯劇團的木偶以精緻的外形和優雅的設計而聞名。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MC_NPC_NULL_NULL","text":{"KOREA":"말씀해 주시죠. 그 인형들은 어떻게 만드시는 건가요?","JPN":"教えてください。その人形はどのようにして作るのですか？","ENG":"Please do tell us, how do you make those puppets?","TWN":"那木偶到底是如何做成的呢？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"간단해요. 아주 특별한 재료들로 만든 인형의 옷을 준비한 다음,","JPN":"簡単です。特別な材料で作った人形の服を用意した後、","ENG":"It's simple. I first prepare their costumes using very special materials...","TWN":"很簡單，首先使用特殊的材料做好木偶的衣服後，"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"인형으로 만들고 싶은 사람들에게 입히면 된답니다.","JPN":"人形にしたい人に、その服を着せればいいんです。","ENG":"and then I simply put them on whoever I want to turn into a puppet.","TWN":"將衣服給想做成木偶的人穿上就可以了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"저기 서 계신 세 분처럼요.","JPN":"あそこに立っている3人の方のようにですね。","ENG":"Like those three ladies over there, for instance.","TWN":"就好像那三位。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭣......?","JPN":"何だと……？","ENG":"What?","TWN":"什麼……？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CINDY_VATICAN_HALLOWEEN_NULL","text":{"KOREA":"윽......! 몸이, 말을 안 듣잖아......!","JPN":"うっ……！　体が動かない……！","ENG":"Ugh! My body... won't respond!","TWN":"呃……！身、身體不聽使喚了……！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CINDY_VATICAN_HALLOWEEN_NULL","face":"UNIT_HATE"},"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_HATE"},"R":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_HALLOWEEN_NULL","text":{"KOREA":"어, 어지러워......","JPN":"め、めまいが……","ENG":"I-I feel dizzy...","TWN":"好、好暈啊……"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"REGINA_ESPR_HALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"INGRID_STREGA_HALLOWEEN_NULL","text":{"KOREA":"뭐, 뭐야......? 갑자기 졸음이......?","JPN":"な、何……？　急に眠くなってきた……？","ENG":"H-huh? Why am I getting sleepy all of a sudden?","TWN":"怎、怎麼回事……？突然這麼睏……？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_HALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"바, 방금 보셨어요? 무대에 있던 세 사람이 모두 쓰러졌어요!","JPN":"い、今の見ましたか？　舞台に立っていた3人がみんな倒れちゃいました！","ENG":"D-did you see that? The three of them just collapsed on stage!","TWN":"妳看見了嗎？舞臺上的三個人都暈倒了！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"라우라! 이건......!","JPN":"ラウラ！　これは……！","ENG":"Laura! Is this what I think it is?","TWN":"蘿拉！這是……！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"<color=#ffd34c>인형의 주인</color>의 수법이야! 얼굴이 달라져서 못 알아봤는데......!","JPN":"<color=#ffd34c>人形の持ち主</color>の手法だ！　顔が変わっていて気づかなかった……！","ENG":"It's the <color=#ffd34c>Puppet Master</color>'s trick! I couldn't recognize her with the new face!","TWN":"這是<color=#ffd34c>木偶之主</color>的手法！我沒認出來那張臉……！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"인형의 주인? 그건 대체......?","JPN":"人形の持ち主？　それはどういう……？","ENG":"Puppet Master? Who's that?","TWN":"木偶之主？那是什麼……？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"쓸데 없는 소리 말고 엎드려!","JPN":"無駄口を叩かずさっさとうつ伏せになれ！","ENG":"Just shut up and get down!","TWN":"廢話少說，快趴下！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"네? 까아악!!","JPN":"え？　きゃあああ！？","ENG":"Huh? Eeek!","TWN":"什麼？呀啊啊！！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐, 뭐야?! 인형들이 괴물로 변하고 있어!","JPN":"な、何だ！？　人形たちが怪物に変わってる！","ENG":"W-what's happening? The puppets are turning into monsters!","TWN":"怎、怎麼回事？！木偶變成了怪物！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HOWLING_01"},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"침식체다! 도망쳐!!","JPN":"侵食体だ！　逃げろ！！","ENG":"They're C.O.s! Run!","TWN":"是侵蝕體！快逃啊！"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HOWLING_02"},{"id":"L42_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"오랜만에 제법 마음에 드는 인형들을 컬렉션에 추가하게 됐네요.","JPN":"久々になかなか気に入った人形をコレクションに追加することができますね。","ENG":"It's been a while since I've added such fine puppets to my collection.","TWN":"好久沒遇到這麼讓人滿意的木偶了。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"그 기념으로 잊을 수 없는 할로윈의 밤을 선사해 드리죠.","JPN":"その記念に忘れられないハロウィンの夜をお贈りしましょう。","ENG":"I will celebrate by offering you a Halloween night you'll never forget.","TWN":"作為紀念，我將賜予你們難忘的萬聖節之夜。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"크로넨워스 극단의 고통과 광란의 퍼레이드.","JPN":"クロネンワース劇団の苦しみと狂気に満ちたパレード。","ENG":"Presenting the parade of suffering and madness by the Cronenworth troupe...","TWN":"克羅尼溫斯劇團的痛苦和狂亂共存的表演。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"부디 즐겨 주시길......","JPN":"どうかご堪能くださいませ。","ENG":"I hope you enjoy.","TWN":"你們好好享受吧……"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};